type NavigateFunc = (to: string, options?: { replace?: boolean } | undefined) => void;

let _navigate: NavigateFunc | null = null;

export const setNavigate = (fn: NavigateFunc) => {
  _navigate = fn;
};

export const navigate = (to: string, options?: { replace?: boolean }) => {
  if (_navigate) {
    try {
      _navigate(to, options);
      return;
    } catch {
      // fallback to location change if react-router navigation fails
    }
  }

  if (options?.replace) {
    globalThis.location.replace(to);
  } else {
    globalThis.location.href = to;
  }
};

export const resetNavigate = () => {
  _navigate = null;
};

/**
 * notifications.ts — Singleton bridge to Ant Design's message/notification APIs.
 *
 * Ant Design v5 requires hook-based `App.useApp()` to display toasts inside the
 * theme context. This bridge captures those APIs once at mount (via
 * <NotificationBridge />) so non-React code (axios interceptors, utils) can
 * still trigger toasts.
 */

type MessageApi = {
  success: (content: string) => void;
  error: (content: string) => void;
  warning: (content: string) => void;
  info: (content: string) => void;
};

let messageApi: MessageApi | null = null;

export function registerMessageApi(api: MessageApi): void {
  messageApi = api;
}

export const notify = {
  success(content: string) {
    if (messageApi) messageApi.success(content);
  },
  error(content: string) {
    if (messageApi) messageApi.error(content);
  },
  warning(content: string) {
    if (messageApi) messageApi.warning(content);
  },
  info(content: string) {
    if (messageApi) messageApi.info(content);
  },
};

/**
 * httpClient.ts — Central axios client
 * - Factory `createApiClient(baseURL?)` that attaches:
 *   - withCredentials: true — sends HttpOnly cookies automatically
 *   - response interceptor: dispatches auth:loggedOut on 401 and redirects to login
 *
 * SECURITY: JWT is stored in HttpOnly cookie (not localStorage).
 * The browser sends the cookie automatically with `withCredentials: true`.
 */
import axios, { isAxiosError as axiosIsAxiosError } from "axios";
import { navigate } from "./navigation";
import { config } from "../../config/env";
import { notify } from "./notifications";

export function createApiClient(baseURL?: string) {
  const api = axios.create({
    baseURL,
    withCredentials: true, // Send HttpOnly cookies with every request
  });

  // Expose a small helper on the created instance so code that imports the
  // client as `axios` can still call `axios.isAxiosError(...)` safely.
  (api as unknown as Record<string, unknown>).isAxiosError = (error: unknown) => {
    try {
      return axiosIsAxiosError ? axiosIsAxiosError(error as Record<string, unknown>) : (error as Record<string, unknown>)?.isAxiosError === true;
    } catch {
      return (error as Record<string, unknown>)?.isAxiosError === true;
    }
  };

  // No request interceptor needed — HttpOnly cookie is sent automatically

  api.interceptors.response.use(
    (response) => response,
    (error) => {
      const status = error?.response?.status;
      const url = error?.config?.url;

      const urlStr = String(url || "");
      const isFormationApi =
        (config?.FORMATION_URL && urlStr.includes(config.FORMATION_URL)) || urlStr.includes("/formation/");

      if (status === 401) {
        if (isFormationApi) {
          return Promise.reject(error);
        }

        try {
          globalThis.dispatchEvent(new Event("auth:loggedOut"));
        } catch {
          /* ignore */
        }
        const isAlreadyOnLogin =
          globalThis.location.pathname === "/" ||
          globalThis.location.pathname.startsWith("/login") ||
          globalThis.location.pathname.startsWith("/auth");
        if (!isAlreadyOnLogin) {
          navigate("/", { replace: true });
        }
      } else if (error?.config?.meta?.silent !== true) {
        // Global UX feedback for unexpected errors. Callers can opt out by
        // passing { meta: { silent: true } } when they handle the error themselves.
        const serverMsg = error?.response?.data?.message;

        if (!error?.response) {
          notify.error("Pas de connexion au serveur. Vérifiez votre réseau.");
        } else if (status >= 500) {
          notify.error(serverMsg || "Erreur serveur. Réessayez dans un instant.");
        } else if (status === 403) {
          notify.warning(serverMsg || "Accès refusé.");
        } else if (status === 422) {
          notify.warning(serverMsg || "Données invalides ou insuffisantes.");
        }
        // 400/404/409 etc. are left to the caller for context-specific handling.
      }
      return Promise.reject(error);
    }
  );

  return api;
}

export const defaultApi = createApiClient();

import type { AxiosResponse } from "axios";
import { createApiClient } from "@/utils/helpers/httpClient";

import { config } from "@/config/env";
import type {
  LoginRequest,
  LoginResponse,
  ResetPasswordRequest,
  SignupRequest,
  AuthUser,
} from "@/models/auth";

const api = createApiClient(`${config.URL_ACCOUNT}/auth`);

/**
 * Authenticate user. JWT is set as HttpOnly cookie by the server.
 * Body returns only userId, role, email, expiresIn — NO token.
 */
export async function login({
  username,
  password,
}: LoginRequest): Promise<LoginResponse> {
  const params = new URLSearchParams();
  params.append("username", username);
  params.append("password", password);
  const response: AxiosResponse<LoginResponse> = await api.post(
    `/login`,
    params
  );

  // JWT is now in HttpOnly cookie — no localStorage
  return response.data;
}

export async function signup(payload: SignupRequest): Promise<unknown> {
  const response = await api.post("/signup", payload);
  return response.data;
}

export async function forgotPassword(emailAddress: string): Promise<unknown> {
  const url = `/forgot-password?emailAddress=${encodeURIComponent(
    emailAddress
  )}`;
  const response = await api.post(url);
  return response.data;
}

export async function resetPassword({
  confirmationKey,
  newPassword,
}: ResetPasswordRequest): Promise<unknown> {
  const response = await api.post(`/reset-password`, {
    confirmationKey,
    newPassword,
  });
  return response.data;
}

export async function getProfile(): Promise<AuthUser> {
  const response = await api.get("/profile");
  return response.data;
}

/**
 * Refresh JWT cookie silently. Server validates existing cookie
 * and returns a new one.
 */
export async function refreshToken(): Promise<LoginResponse> {
  const response: AxiosResponse<LoginResponse> = await api.get("/refresh");
  return response.data;
}

/**
 * Logout — server invalidates the HttpOnly cookie (Max-Age=0).
 */
export async function logout(): Promise<void> {
  await api.post("/logout");
}

import { useState, useMemo, useEffect, useCallback, useRef, createContext } from "react";
import { flushSync } from "react-dom";
import type { ReactNode } from "react";
import type { AuthUser, AuthContextValue, UserRole } from "@/models/auth";
import { refreshToken as refreshTokenApi, logout as logoutApi } from "@/services/auth/AuthService";

export const AuthContext = createContext<AuthContextValue | undefined>(undefined);

interface AuthProviderProps {
  children: ReactNode;
}

/** Silent refresh interval: 100 minutes (JWT lasts 120 min) */
const REFRESH_INTERVAL_MS = 100 * 60 * 1000;

const AuthProvider = ({ children }: AuthProviderProps) => {
  const [user, setUser] = useState<AuthUser | null>(() => {
    const storedUser = sessionStorage.getItem("d2f_user");
    if (storedUser) {
      try {
        return JSON.parse(storedUser) as AuthUser;
      } catch {
        sessionStorage.removeItem("d2f_user");
      }
    }
    return null;
  });

  const refreshTimerRef = useRef<ReturnType<typeof setInterval> | null>(null);

  const stopSilentRefresh = useCallback(() => {
    if (refreshTimerRef.current) {
      clearInterval(refreshTimerRef.current);
      refreshTimerRef.current = null;
    }
  }, []);

  const startSilentRefresh = useCallback(() => {
    if (refreshTimerRef.current) {
      clearInterval(refreshTimerRef.current);
    }
    refreshTimerRef.current = setInterval(() => {
      refreshTokenApi()
        .then((data) => {
          const updatedUser: AuthUser = {
            userId: data.userId,
            username: data.username,
            role: data.role,
            email: data.email,
            expiresIn: data.expiresIn,
          };
          setUser(updatedUser);
          try {
            sessionStorage.setItem("d2f_user", JSON.stringify(updatedUser));
          } catch {
            /* ignore */
          }
        })
        .catch(() => {
          stopSilentRefresh();
          setUser(null);
          sessionStorage.removeItem("d2f_user");
          try {
            globalThis.dispatchEvent(new Event("auth:loggedOut"));
          } catch {
            /* ignore */
          }
        });
    }, REFRESH_INTERVAL_MS);
  }, [stopSilentRefresh]);

  useEffect(() => {
    if (user) {
      startSilentRefresh();
    }
    return () => stopSilentRefresh();
  }, [user, startSilentRefresh, stopSilentRefresh]);

  useEffect(() => {
    if (user) {
      refreshTokenApi()
        .then((data) => {
          const updatedUser: AuthUser = {
            userId: data.userId,
            username: data.username,
            role: data.role as UserRole,
            email: data.email,
            expiresIn: data.expiresIn,
          };
          setUser(updatedUser);
          try {
            sessionStorage.setItem("d2f_user", JSON.stringify(updatedUser));
          } catch {
            /* ignore */
          }
        })
        .catch(() => {
          setUser(null);
          sessionStorage.removeItem("d2f_user");
        });
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  useEffect(() => {
    const onAuthLoggedOut = () => {
      stopSilentRefresh();
      sessionStorage.removeItem("d2f_user");
      try {
        flushSync(() => setUser(null));
      } catch {
        setUser(null);
      }
    };
    globalThis.addEventListener("auth:loggedOut", onAuthLoggedOut);
    return () => globalThis.removeEventListener("auth:loggedOut", onAuthLoggedOut);
  }, [stopSilentRefresh]);

  const login = useCallback((userData: AuthUser) => {
    try {
      sessionStorage.setItem("d2f_user", JSON.stringify(userData));
    } catch {
      /* ignore */
    }
    try {
      flushSync(() => setUser(userData));
    } catch {
      setUser(userData);
    }
    startSilentRefresh();
  }, [startSilentRefresh]);

  const logout = useCallback(() => {
    stopSilentRefresh();
    logoutApi()
      .catch(() => { /* ignore */ })
      .finally(() => {
        sessionStorage.removeItem("d2f_user");
        try {
          flushSync(() => setUser(null));
        } catch {
          setUser(null);
        }
      });
  }, [stopSilentRefresh]);

  const authValue = useMemo<AuthContextValue>(
    () => ({ user, login, logout }),
    [user, login, logout]
  );

  return <AuthContext.Provider value={authValue}>{children}</AuthContext.Provider>;
};

export default AuthProvider;

/**
 * excelExport.js — Utilitaire centralisé pour les exports Excel stylisés
 * Design : couleurs Esprit, en-têtes rouge marque, lignes alternées, bordures fines.
 */
import * as XLSX from "xlsx";

// ── Palette ────────────────────────────────────────────────────────────────
const C = {
  brand:       "B51200",   // rouge Esprit
  brandLight:  "FDECEA",   // fond clair marque
  white:       "FFFFFF",
  rowOdd:      "FFFFFF",
  rowEven:     "FFF8F7",   // très légèrement rosé
  border:      "E0E0E0",
  textDark:    "1F2937",
  textMuted:   "6B7280",
};

const border = (rgb = C.border) => ({ style: "thin", color: { rgb } });
const allBorders = { top: border(), bottom: border(), left: border(), right: border() };

// ── Calcul automatique de largeur de colonne ───────────────────────────────
function autoColWidths(keys, rows) {
  return keys.map(key => ({
    wch: Math.max(
      String(key).length + 2,
      ...rows.map(r => String(r[key] ?? "").length)
    ) + 3,
  }));
}

// ── Feuille stylisée ───────────────────────────────────────────────────────
/**
 * @param {object[]} rows     Données à exporter (tableau d'objets plats)
 * @param {object}   opts
 *   title    {string}  Titre du rapport (ligne fusionnée, fond rouge)
 *   subtitle {string}  Sous-titre (date d'export, filtres actifs…)
 */
export function styledSheet(rows, { title, subtitle } = {}) {
  if (!rows || rows.length === 0) {
    const ws = XLSX.utils.aoa_to_sheet([["Aucune donnée"]]);
    return ws;
  }

  const keys = Object.keys(rows[0]);
  const ncols = keys.length;
  const hasTitle = Boolean(title);
  const hasSub   = Boolean(subtitle);

  // Construire le tableau de tableaux (AOA)
  const aoa = [];
  if (hasTitle) aoa.push([title,    ...Array(ncols - 1).fill(null)]);
  if (hasSub)   aoa.push([subtitle, ...Array(ncols - 1).fill(null)]);
  aoa.push(keys);                                         // en-tête colonnes
  rows.forEach(r => aoa.push(keys.map(k => r[k] ?? ""))); // données

  const ws = XLSX.utils.aoa_to_sheet(aoa);

  // Fusions pour titre / sous-titre
  ws["!merges"] = [];
  let metaRows = 0;
  if (hasTitle) { ws["!merges"].push({ s: { r: metaRows, c: 0 }, e: { r: metaRows, c: ncols - 1 } }); metaRows++; }
  if (hasSub)   { ws["!merges"].push({ s: { r: metaRows, c: 0 }, e: { r: metaRows, c: ncols - 1 } }); metaRows++; }

  const headerRow = metaRows; // index de la ligne d'en-tête colonnes

  // Appliquer les styles cellule par cellule
  aoa.forEach((rowArr, R) => {
    rowArr.forEach((_, C_) => {
      const addr = XLSX.utils.encode_cell({ r: R, c: C_ });
      if (!ws[addr]) return;

      if (hasTitle && R === 0) {
        ws[addr].s = {
          fill: { fgColor: { rgb: C.brand } },
          font: { bold: true, sz: 14, color: { rgb: C.white }, name: "Calibri" },
          alignment: { horizontal: "center", vertical: "center" },
        };
      } else if (hasSub && R === (hasTitle ? 1 : 0)) {
        ws[addr].s = {
          fill: { fgColor: { rgb: C.brandLight } },
          font: { sz: 9, italic: true, color: { rgb: C.textMuted }, name: "Calibri" },
          alignment: { horizontal: "center", vertical: "center" },
        };
      } else if (R === headerRow) {
        ws[addr].s = {
          fill: { fgColor: { rgb: C.brand } },
          font: { bold: true, sz: 11, color: { rgb: C.white }, name: "Calibri" },
          border: allBorders,
          alignment: { horizontal: "center", vertical: "center", wrapText: true },
        };
      } else {
        const dataIdx = R - headerRow;
        ws[addr].s = {
          fill: { fgColor: { rgb: dataIdx % 2 === 1 ? C.rowEven : C.rowOdd } },
          font: { sz: 10, color: { rgb: C.textDark }, name: "Calibri" },
          border: allBorders,
          alignment: { vertical: "center" },
        };
      }
    });
  });

  // Hauteurs de lignes
  ws["!rows"] = aoa.map((_, R) => {
    if (hasTitle && R === 0) return { hpt: 30 };
    if (hasSub && R === (hasTitle ? 1 : 0)) return { hpt: 16 };
    if (R === headerRow) return { hpt: 22 };
    return { hpt: 18 };
  });

  // Largeurs de colonnes
  ws["!cols"] = autoColWidths(keys, rows);

  return ws;
}

// ── Écriture du fichier ────────────────────────────────────────────────────
/**
 * @param {Array<{name: string, rows: object[], title?: string, subtitle?: string}>} sheets
 * @param {string} filename
 */
export function writeExcel(sheets, filename) {
  const wb = XLSX.utils.book_new();
  sheets.forEach(({ name, rows, title, subtitle }) => {
    const ws = styledSheet(rows, { title, subtitle });
    XLSX.utils.book_append_sheet(wb, ws, name);
  });
  XLSX.writeFile(wb, filename, { cellStyles: true });
}

// ── Helper date ────────────────────────────────────────────────────────────
export function exportDateLabel() {
  return `Généré le ${new Date().toLocaleDateString("fr-FR", {
    day: "2-digit", month: "long", year: "numeric",
  })} à ${new Date().toLocaleTimeString("fr-FR", { hour: "2-digit", minute: "2-digit" })}`;
}

export function isoDate() {
  return new Date().toISOString().slice(0, 10);
}

import { defaultApi as axios } from "@/utils/helpers/httpClient";
import type { AxiosResponse } from "axios";
import { config } from "@/config/env";
import type { Id } from "@/models/common";
import type { Formation } from "@/models/formation";

const API_URL = `${config.FORMATION_URL}/formation/formations-workflow`;

// Token is now in HttpOnly cookie, sent automatically via withCredentials: true.

type Presence = unknown;
type FormationWorkflowPayload = Record<string, unknown>;

function normalizeListResponse(payload: unknown): Formation[] {
  if (Array.isArray(payload)) {
    return payload as Formation[];
  }

  if (payload && typeof payload === "object") {
    const candidate = payload as {
      content?: unknown;
      data?: unknown;
      items?: unknown;
    };

    if (Array.isArray(candidate.content)) {
      return candidate.content as Formation[];
    }
    if (Array.isArray(candidate.data)) {
      return candidate.data as Formation[];
    }
    if (Array.isArray(candidate.items)) {
      return candidate.items as Formation[];
    }
  }

  return [];
}

const FormationWorkflowService = {
  async createFormationWorkflow(
    formationData: FormationWorkflowPayload
  ): Promise<Formation> {
    const response = await axios.post<Formation>(API_URL, formationData);
    return response.data;
  },

  async updateFormationWorkflow(
    id: Id,
    formationData: FormationWorkflowPayload
  ): Promise<Formation> {
    const response = await axios.put<Formation>(`${API_URL}/${id}`, formationData);
    return response.data;
  },

  async deleteFormationWorkflow(id: Id): Promise<unknown> {
    const response = await axios.delete(`${API_URL}/${id}`);
    return response.data;
  },

  async getFormationWorkflowById(id: Id): Promise<Formation> {
    const response = await axios.get<Formation>(`${API_URL}/${id}`);
    return response.data;
  },

  async getAllFormationWorkflows(): Promise<Formation[]> {
    const response = await axios.get<Formation[]>(API_URL);
    return normalizeListResponse(response.data);
  },

  async updatePresence(
    id: Id,
    isPresent: boolean,
    commentaire?: string
  ): Promise<Presence> {
    const response = await axios.put<Presence>(`${API_URL}/presence/${id}`, null, {
      params: { present: isPresent, commentaire },
    });
    return response.data;
  },

  async getPresencesBySeance(seanceId: Id): Promise<Presence[]> {
    const response = await axios.get<Presence[]>(`${API_URL}/seances/${seanceId}/presences`);
    return response.data;
  },

  async batchUpdatePresences(
    seanceId: Id,
    updates: Array<{ idParticipation: number | string; present: boolean; commentaire?: string }>
  ): Promise<Presence[]> {
    const response = await axios.put<Presence[]>(
      `${API_URL}/seances/${seanceId}/presences/batch`,
      { updates }
    );
    return response.data;
  },

  async markAllPresences(seanceId: Id, present: boolean): Promise<Presence[]> {
    const response = await axios.put<Presence[]>(
      `${API_URL}/seances/${seanceId}/presences/mark-all`,
      null,
      { params: { present } }
    );
    return response.data;
  },

  async getSeancePresenceStats(seanceId: Id): Promise<{
    seanceId: number;
    total: number;
    presents: number;
    absents: number;
    tauxPresence: number;
  }> {
    const response = await axios.get(`${API_URL}/seances/${seanceId}/presences/stats`);
    return response.data as {
      seanceId: number;
      total: number;
      presents: number;
      absents: number;
      tauxPresence: number;
    };
  },

  async getFormationsByAnimateur(): Promise<Formation[]> {
    const response = await axios.get<Formation[]>(`${API_URL}/animateur`);
    return normalizeListResponse(response.data);
  },

  async getFormationsAchevees(): Promise<Formation[]> {
    const response = await axios.get<Formation[]>(`${API_URL}/achevees`);
    return normalizeListResponse(response.data);
  },

  async getAllFormationWithDocuments(): Promise<Formation[]> {
    const response = await axios.get<Formation[]>(`${API_URL}/with-documents`);
    return normalizeListResponse(response.data);
  },

  // Backward-compatible alias used by some legacy pages.
  async getAllFormationsWithDocuments(): Promise<Formation[]> {
    return FormationWorkflowService.getAllFormationWithDocuments();
  },

  async getFormationsForCalendar(enseignantId: Id): Promise<Formation[]> {
    const response = await axios.get<Formation[]>(
      `${API_URL}/enseignants/${enseignantId}/calendar`
    );
    return normalizeListResponse(response.data);
  },

  async updateInscriptionsOuvertes(id: Id, ouvert: boolean): Promise<Formation> {
    const response = await axios.put<Formation>(
      `${API_URL}/${id}/inscriptionsOuvertes`,
      null,
      { params: { ouvert } }
    );
    return response.data;
  },

  async getFormationsVisibles(): Promise<Formation[]> {
    const response = await axios.get<Formation[]>(`${API_URL}/visibles`);
    return normalizeListResponse(response.data);
  },

  async getFormationsParUp(upId: Id): Promise<Formation[]> {
    const response = await axios.get<Formation[]>(`${API_URL}/par-up`, {
      params: { upId },
    });
    return normalizeListResponse(response.data);
  },

  async exportFormations(
    start: string,
    end: string
  ): Promise<AxiosResponse<Blob>> {
    return axios.get<Blob>(`${API_URL}/export/excel`, {
      responseType: "blob",
      params: { start, end },
    });
  },
  async getFormationsParDepartement(deptId: Id): Promise<Formation[]> {
    const response = await axios.get<Formation[]>(`${API_URL}/par-departement`, {
      params: { deptId },
    });
    return normalizeListResponse(response.data);
  },
};

export default FormationWorkflowService;

import { defaultApi as axios } from "@/utils/helpers/httpClient";
import { config } from "@/config/env";
const API_URL = `${config.FORMATION_URL}/formation/departements`;

function normalizeListResponse<T>(payload: T[] | { content?: T[]; data?: T[]; items?: T[] }): T[] {
  if (Array.isArray(payload)) {
    return payload;
  }

  if (payload && typeof payload === "object") {
    const candidate = payload as { content?: unknown[]; data?: unknown[]; items?: unknown[] };
    if (Array.isArray(candidate.content)) {
      return candidate.content as T[];
    }
    if (Array.isArray(candidate.data)) {
      return candidate.data as T[];
    }
    if (Array.isArray(candidate.items)) {
      return candidate.items as T[];
    }
  }

  return [];
}

function isNotFoundError(error: unknown): boolean {
  return (error as { isAxiosError?: boolean; response?: { status?: number } })?.isAxiosError === true
    && (error as { response?: { status?: number } })?.response?.status === 404;
}

const DeptService = {
  async createDept(deptData: Record<string, unknown>) {
    try {
      const response = await axios.post(API_URL, deptData);
      return response.data;
    } catch (error) {
      throw error;
    }
  },

  async getAllDepts() {
    try {
      const response = await axios.get(API_URL);
      return normalizeListResponse(response.data);
    } catch (error) {
      if (isNotFoundError(error)) {
        return [];
      }
      throw error;
    }
  },

  async getDeptById(id: number | string) {
    try {
      const response = await axios.get(`${API_URL}/${id}`);
      return response.data;
    } catch (error) {
      throw error;
    }
  },

  async updateDept(id: number | string, deptData: Record<string, unknown>) {
    try {
      const response = await axios.put(`${API_URL}/${id}`, deptData);
      return response.data;
    } catch (error) {
      throw error;
    }
  },

  async deleteDept(id: number | string) {
    try {
      await axios.delete(`${API_URL}/${id}`);
    } catch (error) {
      throw error;
    }
  },

  async importDeptsExcel(file: File) {
    try {
      const formData = new FormData();
      formData.append("file", file);
      const response = await axios.post(`${API_URL}/import-excel`, formData);
      return response.data;
    } catch (error) {
      throw error;
    }
